"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[39933],{38554:e=>{e.exports=JSON.parse('{"tag":{"label":"placement","permalink":"/dst-api-webdocs/docs/tags/placement","allTagsPath":"/dst-api-webdocs/docs/tags","count":14,"items":[{"id":"game-scripts/prefabs/boatrace_common","title":"Boatrace Common","description":"Provides utility functions and prefab factories for boat race events, including deploy helper visuals, throwable deploy kits, and placement validation logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_common"},{"id":"game-scripts/prefabs/carnivalgame_placementblocker","title":"Carnivalgame Placementblocker","description":"Provides a non-interactive, non-persistent placeholder entity used during carnival game setup to block placement and mark valid locations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_placementblocker"},{"id":"game-scripts/components/deployable","title":"Deployable","description":"Manages deployment behavior and constraints for inventory items that can be placed into the world, such as walls, plants, boats, and masts.","permalink":"/dst-api-webdocs/docs/game-scripts/components/deployable"},{"id":"game-scripts/prefabs/fence","title":"Fence","description":"Provides base prefab construction logic for walls, fences, and gates, including alignment, rotation, locking, and component setup.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fence"},{"id":"game-scripts/prefabs/gridplacer","title":"Gridplacer","description":"A visual helper component used during building placement to show grid-aligned placement outlines and handle build validation feedback via color changes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gridplacer"},{"id":"game-scripts/prefabs/hermitcrab_relocation_kit","title":"Hermitcrab Relocation Kit","description":"A deployable inventory item used to pre-configure and place hermit crab structures and markers on a forest island, coordinated via the hermitcrab_relocation_manager component.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrab_relocation_kit"},{"id":"game-scripts/map/placement","title":"Placement","description":"Provides procedural positioning utilities for map nodes using various spatial distribution algorithms (random line, circular offset, circular edge) and two placement strategies (mode0, random).","permalink":"/dst-api-webdocs/docs/game-scripts/map/placement"},{"id":"game-scripts/components/placer","title":"Placer","description":"Manages placement positioning, orientation, and visual feedback for deployable structures and items in the game world, including support for axis-aligned placement and boat edge snapping.","permalink":"/dst-api-webdocs/docs/game-scripts/components/placer"},{"id":"game-scripts/prefabs/reticuleaoe","title":"Reticuleaoe","description":"Factory function that creates prefabs for area-of-effect visual indicators (reticules, pings, and targets) used in placement and targeting interfaces.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/reticuleaoe"},{"id":"game-scripts/prefabs/rope_bridge","title":"Rope Bridge","description":"Manages the visual and functional representation of rope bridges in the world, including placement, animation states, and interaction with the rope bridge placement system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rope_bridge"},{"id":"game-scripts/prefabs/turfs","title":"Turfs","description":"Generates prefabs for ground tile items that can be placed on the map to replace existing tiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/turfs"},{"id":"game-scripts/prefabs/wagpunk_floor_kit","title":"Wagpunk Floor Kit","description":"Deploys permanent ocean-floor floor tiles in Wagstaff Arena areas, replacing tiles and salvaging any submerged objects found beneath them.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagpunk_floor_kit"},{"id":"game-scripts/prefabs/wendy_recipe_gravestone","title":"Wendy Recipe Gravestone","description":"Acts as an intermediate placeholder prefab used to spawn Wendy\u2019s gravestone, supporting ghost skeleton snapping, writing, and transition to the final gravestone prefab.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wendy_recipe_gravestone"},{"id":"game-scripts/prefabs/yotb_placer_common","title":"Yotb Placer Common","description":"Provides helper functions and constants to manage placement preview rings for deployable prefabs in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotb_placer_common"}],"unlisted":false}}')}}]);